// Normaliza leads do RD Station e ordena cronologicamente.
// Entrada: cada item tem { body: { leads: [...] } }.
// Saída: 1 item por lead, ordenados por RD created_at ASC.

const mapModalidade = {
  'tenis': 'tenis', 'tênis': 'tenis',
  'padel': 'padel', 'pádel': 'padel', 'paddle': 'padel',
  'beach tennis': 'beachtennis', 'beach tenis': 'beachtennis',
  'beach-tennis': 'beachtennis', 'beachtennis': 'beachtennis'
};

const mapTurno = {
  '9h': '9h', '09h': '9h', '09:00': '9h', '9:00': '9h', '9': '9h',
  '10h': '10h', '10:00': '10h', '10': '10h',
  '11h': '11h', '11:00': '11h', '11': '11h'
};

const norm = (v) => (v ?? '').toString().trim().toLowerCase();

const readCF = (cf, keys) => {
  if (!cf) return null;
  for (const k of keys) {
    if (cf[k] !== undefined && cf[k] !== null && cf[k] !== '') return cf[k];
  }
  return null;
};

const results = [];

for (const input of $input.all()) {
  const data = input.json || {};
  const leads = data?.body?.leads
              ?? data?.leads
              ?? (Array.isArray(data) ? data : [data]);

  for (const lead of leads) {
    if (!lead || typeof lead !== 'object') continue;

    const cf = lead.custom_fields || {};
    const convPayload = lead?.first_conversion?.content?.__cdp__original_event?.payload || {};

    const modalidadeRaw = norm(
      readCF(cf, [
        '[Open All Resort] Clínica escolhida',
        '[Open All Resort] Clinica escolhida',
        'cf_open_all_resort_clinica_escolhida',
        'modalidade'
      ]) || convPayload.cf_open_all_resort_clinica_escolhida
    );

    const turnoRaw = norm(
      readCF(cf, [
        '[Open All Resort] Horário',
        '[Open All Resort] Horario',
        'cf_open_all_resort_horario',
        'horario', 'turno'
      ]) || convPayload.cf_open_all_resort_horario
    );

    const tipoRaw = norm(
      readCF(cf, [
        '[Open All Resort] Tipo de Participação',
        '[Open All Resort] Tipo de Participacao',
        'cf_open_all_resort_tipo_de_participacao',
        'tipo_participacao'
      ]) || convPayload.cf_open_all_resort_tipo_de_participacao || 'jogador'
    );

    const nome = (lead.name || '').trim();
    const email = (lead.email || '').trim();

    if (!nome || !email) continue;

    results.push({
      json: {
        nome,
        email,
        telefone: lead.mobile_phone || lead.personal_phone || null,
        cidade: lead.city || null,
        area_profissional: lead.job_title || lead.bio || null,
        tipo_participacao: tipoRaw.includes('acompanh') ? 'acompanhante' : 'jogador',
        modalidade: mapModalidade[modalidadeRaw] || null,
        turno: mapTurno[turnoRaw] || null,
        rd_uuid: lead.uuid || null,
        rd_conversion_identifier: lead?.last_conversion?.source
                                || lead?.first_conversion?.source
                                || 'All resort página evento',
        origem: 'rd_station',
        raw_payload: lead
      }
    });
  }
}

// Ordena cronologicamente — quem se inscreveu primeiro no RD entra primeiro,
// garantindo que os 8 primeiros de Tênis 9h sejam 'confirmado' e o resto 'suplente'.
results.sort((a, b) => {
  const ca = a.json.raw_payload?.created_at || '';
  const cb = b.json.raw_payload?.created_at || '';
  return ca.localeCompare(cb);
});

return results;
